INSERT INTO public.medical_knowledge (category, condition, keywords, title, content, language, source, priority, is_active) VALUES
('clinical_guideline','copd_management',ARRAY['copd','chronic obstructive','emphysema','chronic bronchitis','spirometry'],'COPD Management','E''## COPD Management\n\n### Classification (GOLD)\n- GOLD 1: FEV1 ≥80% predicted\n- GOLD 2: 50-79%\n- GOLD 3: 30-49%\n- GOLD 4: <30%\n\n### Treatment\n- **Mild**: SABA PRN (Salbutamol)\n- **Moderate**: Add LABA (Formoterol) or LAMA (Tiotropium)\n- **Severe**: LABA + LAMA + ICS\n- **Very severe**: Add roflumilast, consider O2 therapy\n\n### Non-pharmacological\n- Smoking cessation (most important)\n- Pulmonary rehabilitation\n- Annual influenza + pneumococcal vaccine\n- Oxygen if PaO2 <55mmHg''','en','GOLD/NICE',6,true),
('clinical_guideline','anemia_workup',ARRAY['anemia','low hemoglobin','iron deficiency','pallor','fatigue'],'Anemia Workup','E''## Anemia Workup\n\n### Classification by MCV\n- **Microcytic (MCV<80)**: Iron deficiency, thalassemia, chronic disease\n- **Normocytic (MCV 80-100)**: Chronic disease, renal failure, acute blood loss\n- **Macrocytic (MCV>100)**: B12/folate deficiency, hypothyroidism, liver disease\n\n### Initial Labs\n- CBC with indices, reticulocyte count\n- Iron studies (ferritin, TIBC, serum iron)\n- B12, folate levels\n- Peripheral smear\n\n### Iron Deficiency Treatment\n- Ferrous sulfate 325mg TID (65mg elemental iron)\n- Take with vitamin C, avoid with tea/milk\n- Recheck Hb in 4-6 weeks\n- IV iron if oral intolerant or severe''','en','WHO',6,true),
('clinical_guideline','thyroid_disorders',ARRAY['thyroid','hypothyroidism','hyperthyroidism','TSH','goiter','levothyroxine'],'Thyroid Disorders','E''## Thyroid Disorders\n\n### Hypothyroidism\n- **Symptoms**: Fatigue, weight gain, cold intolerance, constipation\n- **Diagnosis**: TSH elevated, free T4 low\n- **Treatment**: Levothyroxine 1.6 mcg/kg/day\n- Take on empty stomach, 30min before food\n- Recheck TSH in 6-8 weeks\n\n### Hyperthyroidism\n- **Symptoms**: Weight loss, tremor, heat intolerance, palpitations\n- **Diagnosis**: TSH suppressed, free T4/T3 elevated\n- **Treatment**: Carbimazole 15-40mg/day or PTU\n- Beta-blocker for symptom control\n- Consider radioactive iodine or surgery''','en','ATA',6,true),
('clinical_guideline','depression_screening',ARRAY['depression','PHQ-9','mental health','SSRI','suicidal','mood disorder'],'Depression Screening (PHQ-9)','E''## Depression Screening\n\n### PHQ-9 Scoring\n- 0-4: Minimal\n- 5-9: Mild – watchful waiting, counseling\n- 10-14: Moderate – consider medication\n- 15-19: Moderately severe – medication + therapy\n- 20-27: Severe – urgent psychiatric referral\n\n### First-Line Treatment\n- SSRIs: Fluoxetine 20mg, Sertraline 50mg, Escitalopram 10mg\n- Start low, increase after 2-4 weeks\n- Minimum 6 months treatment after remission\n\n### Safety\n- Always screen for suicidal ideation\n- Ask about plan and access to means\n- Urgent referral if active suicidal thoughts''','en','APA/NICE',6,true),
('clinical_guideline','pediatric_diarrhea',ARRAY['diarrhea','ORS','dehydration','pediatric','rotavirus','zinc'],'Pediatric Diarrhea & ORS','E''## Pediatric Diarrhea Management\n\n### Dehydration Assessment\n- **No dehydration**: Alert, drinks normally, skin pinch normal → Plan A\n- **Some dehydration**: Restless, thirsty, skin pinch slow → Plan B\n- **Severe**: Lethargic, unable to drink, skin pinch very slow → Plan C\n\n### Plan A (Home)\n- ORS after each loose stool: <2yr: 50-100ml, 2-10yr: 100-200ml\n- Continue breastfeeding\n- Zinc: <6mo: 10mg/day, >6mo: 20mg/day × 10-14 days\n\n### Plan B (Clinic)\n- ORS 75ml/kg over 4 hours\n- Reassess after 4 hours\n\n### Plan C (Hospital)\n- IV Ringer lactate 100ml/kg: <12mo over 6hr, >12mo over 3hr''','en','WHO/IMCI',6,true),
('clinical_guideline','malaria_treatment',ARRAY['malaria','plasmodium','ACT','artemisinin','chloroquine','fever'],'Malaria Treatment','E''## Malaria Treatment\n\n### Uncomplicated P. falciparum\n- **First-line**: ACT (Artemether-Lumefantrine)\n- Dose: Weight-based, 6 doses over 3 days\n- Take with fatty food for absorption\n\n### Uncomplicated P. vivax\n- Chloroquine 25mg base/kg over 3 days\n- Plus Primaquine 0.25mg/kg/day × 14 days (radical cure)\n- Check G6PD before primaquine\n\n### Severe Malaria\n- IV Artesunate 2.4mg/kg at 0, 12, 24hr then daily\n- Switch to oral ACT when able to eat\n- Monitor blood glucose, Hb, parasitemia\n\n### Prevention\n- ITN (insecticide-treated nets)\n- IPTp for pregnant women''','en','WHO',6,true),
('clinical_guideline','tb_screening',ARRAY['tuberculosis','TB','sputum','AFB','rifampicin','isoniazid','DOT'],'TB Screening & Treatment','E''## TB Screening & Treatment\n\n### Screening\n- Cough >2 weeks + any of: weight loss, night sweats, fever, hemoptysis\n- Sputum AFB ×3 (spot-morning-spot)\n- GeneXpert MTB/RIF (preferred)\n- Chest X-ray\n\n### Treatment (Drug-Susceptible)\n- **Intensive phase (2 months)**: RHZE\n  - Rifampicin + Isoniazid + Pyrazinamide + Ethambutol\n- **Continuation phase (4 months)**: RH\n- DOT (Directly Observed Therapy)\n\n### Monitoring\n- Sputum at 2, 5, 6 months\n- LFTs monthly (hepatotoxicity risk)\n- Visual acuity (ethambutol)\n- Pyridoxine 25mg/day to prevent neuropathy''','en','WHO',6,true),
('clinical_guideline','wound_care',ARRAY['wound','laceration','suture','tetanus','infection','debridement'],'Wound Care','E''## Wound Management\n\n### Initial Assessment\n- Control bleeding with direct pressure\n- Assess depth, contamination, neurovascular status\n- Check tetanus status\n\n### Cleaning\n- Irrigate with normal saline under pressure\n- Debride devitalized tissue\n- Remove foreign bodies\n\n### Closure\n- **Primary closure**: Clean wounds <6-8 hours old\n- **Delayed closure**: Contaminated wounds, bites\n- **Secondary intention**: Heavily contaminated, abscess cavities\n\n### Tetanus Prophylaxis\n- Clean wound + >5yr since booster → Td vaccine\n- Dirty wound + >5yr → Td + TIG\n- Unknown vaccination → Full series + TIG\n\n### Antibiotics\n- Not routine for clean wounds\n- Give for: bites, crush injuries, immunocompromised''','en','WHO',6,true),
('clinical_guideline','burns_management',ARRAY['burn','scald','thermal injury','BSA','fluid resuscitation','silver sulfadiazine'],'Burns Management','E''## Burns Management\n\n### Classification\n- **Superficial**: Red, painful, no blisters (sunburn)\n- **Partial thickness**: Blisters, very painful, moist\n- **Full thickness**: White/charred, painless, dry\n\n### BSA Estimation (Rule of 9s - Adults)\n- Head: 9%, Each arm: 9%, Each leg: 18%\n- Anterior trunk: 18%, Posterior trunk: 18%\n- Palm of patient = ~1% BSA\n\n### Fluid Resuscitation (Parkland Formula)\n- 4ml × kg × %BSA over 24 hours\n- Half in first 8 hours, half in next 16 hours\n- Use Ringer Lactate\n\n### Referral Criteria\n- >20% BSA (>10% in children)\n- Full thickness >5%\n- Face, hands, feet, genitalia, joints\n- Inhalation injury, electrical, chemical burns''','en','WHO/ABA',6,true),
('clinical_guideline','fracture_first_aid',ARRAY['fracture','broken bone','splint','immobilization','orthopedic','trauma'],'Fracture First Aid','E''## Fracture First Aid\n\n### Recognition\n- Pain, swelling, deformity, loss of function\n- Crepitus (do not deliberately elicit)\n- Open fracture: bone visible through skin\n\n### Immediate Management\n- Immobilize above and below fracture site\n- Splint in position found (do not reduce in field)\n- Ice pack (20min on, 20min off)\n- Elevate if possible\n- Check distal pulse, sensation, movement\n\n### Open Fractures\n- Cover with sterile moist dressing\n- Do NOT push bone back\n- IV antibiotics within 1 hour\n- Tetanus prophylaxis\n- Surgical debridement within 6 hours\n\n### X-ray\n- Two views (AP + lateral)\n- Include joint above and below''','en','ATLS',6,true),
('clinical_guideline','hiv_pep',ARRAY['HIV','PEP','post-exposure','antiretroviral','needle stick','sexual assault'],'HIV PEP','E''## HIV Post-Exposure Prophylaxis\n\n### Indications\n- Needle-stick injury from HIV+ source\n- Sexual assault\n- Unprotected sex with known HIV+ partner\n\n### Timing\n- Start within 72 hours (ideally <2 hours)\n- 28-day course\n\n### Regimen\n- TDF/FTC (Tenofovir + Emtricitabine) + Dolutegravir\n- Or TDF/3TC + Dolutegravir\n\n### Baseline Tests\n- HIV test (must be negative to start PEP)\n- Hepatitis B, C serology\n- Creatinine, LFTs\n- Pregnancy test (women)\n\n### Follow-up\n- HIV test at 6 weeks, 3 months, 6 months\n- Adherence support\n- Counseling''','en','WHO',6,true),
('clinical_guideline','uti_management',ARRAY['UTI','urinary tract infection','dysuria','cystitis','pyelonephritis','nitrofurantoin'],'UTI Management','E''## UTI Management\n\n### Uncomplicated Cystitis (Women)\n- **First-line**: Nitrofurantoin 100mg BD × 5 days\n- **Alternative**: TMP-SMX 160/800mg BD × 3 days\n- **If allergic**: Fosfomycin 3g single dose\n\n### Complicated UTI / Pyelonephritis\n- Ciprofloxacin 500mg BD × 7-14 days\n- Or IV Ceftriaxone if unable to take oral\n- Blood cultures if systemic symptoms\n\n### UTI in Pregnancy\n- Nitrofurantoin (avoid at term)\n- Amoxicillin-clavulanate\n- Cephalexin 500mg QID × 7 days\n- Always treat asymptomatic bacteriuria\n\n### Recurrent UTI (≥3/year)\n- Post-coital prophylaxis\n- Cranberry supplements\n- Low-dose prophylaxis: Nitrofurantoin 50mg nightly × 6 months''','en','NICE/IDSA',6,true),
('clinical_guideline','childhood_vaccination',ARRAY['vaccine','immunization','EPI','childhood','BCG','pentavalent','measles'],'Childhood Vaccination Schedule','E''## EPI Vaccination Schedule\n\n### Birth\n- BCG, OPV-0, Hepatitis B (within 24 hours)\n\n### 6 Weeks\n- Pentavalent-1 (DPT+HepB+Hib)\n- OPV-1, PCV-1, Rotavirus-1\n\n### 10 Weeks\n- Pentavalent-2, OPV-2, PCV-2, Rotavirus-2\n\n### 14 Weeks\n- Pentavalent-3, OPV-3, PCV-3, IPV-1\n\n### 9 Months\n- Measles-1, Vitamin A\n\n### 15 Months\n- Measles-2\n\n### Cold Chain\n- Store vaccines 2-8°C\n- Never freeze PCV, Pentavalent, IPV\n- Use VVM (vaccine vial monitor)\n\n### Contraindications\n- Anaphylaxis to previous dose\n- Severe immunodeficiency (live vaccines)\n- NOT contraindicated: mild illness, antibiotics, malnutrition''','en','WHO/EPI',6,true),
('clinical_guideline','diabetic_foot',ARRAY['diabetic foot','foot ulcer','neuropathy','peripheral vascular','amputation','wound care'],'Diabetic Foot Care','E''## Diabetic Foot Management\n\n### Risk Assessment (Annual)\n- Monofilament test (10g)\n- Vibration (128Hz tuning fork)\n- Ankle-brachial index\n- Visual inspection\n\n### Classification (Wagner)\n- Grade 0: At risk, no ulcer\n- Grade 1: Superficial ulcer\n- Grade 2: Deep ulcer to tendon/bone\n- Grade 3: Deep with abscess/osteomyelitis\n- Grade 4: Gangrene (partial)\n- Grade 5: Gangrene (whole foot)\n\n### Management\n- Offloading (therapeutic footwear)\n- Debridement of necrotic tissue\n- Moist wound dressing\n- Antibiotics if infected\n- Glycemic control (HbA1c <7%)\n\n### Referral\n- Grade 2+ → vascular/orthopedic surgery\n- Charcot foot → urgent specialist''','en','IWGDF',6,true),
('clinical_guideline','acute_coronary',ARRAY['ACS','acute coronary','STEMI','NSTEMI','troponin','aspirin','PCI'],'Acute Coronary Syndrome','E''## Acute Coronary Syndrome\n\n### Classification\n- **STEMI**: ST elevation ≥1mm in 2 contiguous leads\n- **NSTEMI**: Troponin elevated, no ST elevation\n- **Unstable Angina**: No troponin rise\n\n### Immediate Management (MONA)\n- Morphine 2-4mg IV (if pain not controlled)\n- Oxygen (only if SpO2 <94%)\n- Nitrate SL (GTN 0.4mg, avoid if SBP<90)\n- Aspirin 300mg chewed\n\n### STEMI\n- Door-to-balloon <90min (PCI preferred)\n- If PCI not available: Fibrinolysis within 12hr\n- Dual antiplatelet: ASA + Clopidogrel 300mg\n\n### NSTEMI/UA\n- Risk stratify (GRACE score)\n- Anticoagulation (Enoxaparin)\n- High-risk → early invasive strategy\n- Statin, ACEi, beta-blocker''','en','AHA/ESC',6,true),
('clinical_guideline','stroke_management',ARRAY['stroke','CVA','thrombolysis','TIA','hemiplegia','tPA','FAST'],'Stroke Management','E''## Stroke Management\n\n### Recognition (FAST)\n- **F**ace drooping\n- **A**rm weakness\n- **S**peech difficulty\n- **T**ime to call emergency\n\n### Acute Ischemic Stroke\n- CT head to exclude hemorrhage\n- IV tPA (Alteplase) if within 4.5 hours\n- Endovascular thrombectomy if large vessel within 24hr\n- Aspirin 300mg within 48 hours (after CT)\n- Keep BP <185/110 if thrombolysis planned\n\n### Hemorrhagic Stroke\n- Reverse anticoagulation\n- BP control (SBP target <140)\n- Neurosurgery consultation\n- ICP management\n\n### Secondary Prevention\n- Antiplatelet (Aspirin + Clopidogrel 21 days)\n- Statin (Atorvastatin 80mg)\n- BP control, diabetes management\n- Carotid endarterectomy if >70% stenosis''','en','AHA/ASA',6,true);
INSERT INTO public.medical_knowledge (category, condition, keywords, title, content, language, source, priority, is_active) VALUES
('symptom_guide','joint_pain',ARRAY['joint pain','arthritis','arthralgia','swollen joint','stiffness','gout'],'Joint Pain Differentials','E''## Joint Pain Differentials\n\n### Monoarticular (Single Joint)\n- **Septic arthritis**: Hot, red, swollen, fever → EMERGENCY\n- **Gout**: 1st MTP, acute onset, uric acid crystals\n- **Pseudogout**: Knee/wrist, calcium pyrophosphate\n- **Trauma/fracture**: History of injury\n\n### Polyarticular\n- **Rheumatoid arthritis**: Small joints, symmetrical, morning stiffness >1hr\n- **Osteoarthritis**: Weight-bearing joints, worse with activity\n- **Viral arthritis**: Dengue, chikungunya, hepatitis\n- **SLE**: Young women, butterfly rash, ANA+\n\n### Red Flags\n- Hot swollen joint with fever → septic arthritis\n- Joint pain + skin rash → consider reactive/psoriatic\n- Joint pain in children → juvenile arthritis, rheumatic fever''','en','EULAR',5,true),
('symptom_guide','cough_evaluation',ARRAY['cough','chronic cough','productive','dry cough','hemoptysis','wheezing'],'Cough Evaluation','E''## Cough Evaluation\n\n### By Duration\n- **Acute (<3 weeks)**: URTI, pneumonia, COVID, pertussis\n- **Subacute (3-8 weeks)**: Post-infectious, pertussis\n- **Chronic (>8 weeks)**: Asthma, GERD, ACEi, TB\n\n### Common Causes\n- **Productive**: Pneumonia, bronchiectasis, COPD, TB\n- **Dry**: Asthma, ACEi, GERD, interstitial lung disease\n- **Nocturnal**: Asthma, GERD, heart failure\n- **With hemoptysis**: TB, malignancy, PE, bronchiectasis\n\n### Red Flags\n- Hemoptysis → chest X-ray urgently\n- Weight loss + night sweats → TB workup\n- Smoker >3 weeks → malignancy screening\n- Dyspnea + orthopnea → heart failure\n\n### Workup\n- Chest X-ray (first-line)\n- Sputum AFB if >2 weeks\n- Spirometry if asthma suspected''','en','BTS',5,true),
('symptom_guide','dizziness_vertigo',ARRAY['dizziness','vertigo','lightheaded','BPPV','labyrinthitis','syncope'],'Dizziness & Vertigo','E''## Dizziness & Vertigo\n\n### Types\n- **True vertigo**: Room spinning → inner ear/vestibular\n- **Presyncope**: Feeling faint → cardiovascular\n- **Disequilibrium**: Unsteady walking → neurological\n- **Non-specific**: Anxiety, hyperventilation\n\n### Peripheral Vertigo (Common)\n- **BPPV**: Brief episodes with position change, Dix-Hallpike +ve\n- **Labyrinthitis**: Post-viral, hearing loss, tinnitus\n- **Meniere disease**: Episodic vertigo + hearing loss + tinnitus + fullness\n\n### Central Vertigo (Dangerous)\n- **Stroke/TIA**: Sudden, associated neurological deficits\n- **Posterior fossa tumor**: Progressive, headache\n\n### Red Flags\n- New headache + vertigo → stroke/hemorrhage\n- Focal neurological signs → urgent CT/MRI\n- Sudden hearing loss → ENT emergency''','en','AAO-HNS',5,true),
('symptom_guide','palpitations',ARRAY['palpitations','tachycardia','arrhythmia','irregular heartbeat','atrial fibrillation','SVT'],'Palpitations','E''## Palpitations Assessment\n\n### History\n- Onset: sudden vs gradual\n- Duration: seconds (ectopics) vs minutes/hours (SVT/AF)\n- Associated: chest pain, dyspnea, syncope\n- Triggers: caffeine, exercise, stress, alcohol\n\n### Common Causes\n- **Benign**: Ectopic beats (PACs/PVCs), sinus tachycardia, anxiety\n- **SVT**: Regular, fast, sudden onset/offset\n- **Atrial fibrillation**: Irregularly irregular\n- **Ventricular tachycardia**: Wide complex, hemodynamic instability\n\n### Workup\n- 12-lead ECG\n- 24-48hr Holter monitor\n- Thyroid function, electrolytes, CBC\n- Echocardiogram if structural heart disease suspected\n\n### Red Flags\n- Syncope with palpitations → urgent cardiology\n- Family history of sudden death → screening\n- Palpitations during exercise → stress test''','en','ESC',5,true),
('symptom_guide','urinary_symptoms',ARRAY['dysuria','frequency','urgency','hematuria','retention','incontinence','prostate'],'Urinary Symptoms','E''## Urinary Symptoms\n\n### Lower Urinary Tract\n- **Storage**: Frequency, urgency, nocturia, incontinence\n- **Voiding**: Hesitancy, weak stream, intermittency, straining\n\n### Differential Diagnosis\n- **Dysuria + frequency**: UTI, STI (urethritis)\n- **Hematuria**: UTI, stones, malignancy, glomerulonephritis\n- **Retention**: BPH, anticholinergics, neurogenic bladder\n- **Incontinence**: Stress (women), urge (OAB), overflow\n\n### Red Flags\n- Painless gross hematuria in >40 → bladder cancer screening\n- Acute retention → catheterize urgently\n- Hematuria + flank pain → renal stone/tumor\n\n### Workup\n- Urinalysis + culture\n- PSA (men >50 with LUTS)\n- Renal ultrasound\n- Cystoscopy if unexplained hematuria''','en','EAU',5,true),
('symptom_guide','skin_rash',ARRAY['rash','dermatitis','eczema','urticaria','psoriasis','fungal','scabies'],'Skin Rash Differentials','E''## Skin Rash Differentials\n\n### By Morphology\n- **Papules**: Acne, viral warts, molluscum\n- **Vesicles**: Herpes, varicella, contact dermatitis\n- **Plaques**: Psoriasis, eczema, tinea\n- **Wheals**: Urticaria (allergic)\n- **Purpura**: Meningococcemia, ITP, vasculitis\n\n### Common Conditions\n- **Eczema**: Itchy, flexural, atopic history\n- **Psoriasis**: Silvery scales, extensor surfaces, nail pitting\n- **Tinea**: Ring-shaped, scaly border, KOH+\n- **Scabies**: Intense itch (worse at night), burrows, web spaces\n- **Drug eruption**: Recent medication, widespread morbilliform\n\n### Red Flags\n- Purpura + fever → meningococcemia (emergency)\n- Blistering + mucosal involvement → SJS/TEN\n- Rapidly spreading redness + warmth → cellulitis/necrotizing fasciitis''','en','BAD',5,true),
('symptom_guide','eye_redness',ARRAY['red eye','conjunctivitis','glaucoma','uveitis','corneal ulcer','eye pain'],'Eye Redness','E''## Red Eye Differentials\n\n### Common (Non-urgent)\n- **Bacterial conjunctivitis**: Purulent discharge, both eyes\n- **Viral conjunctivitis**: Watery discharge, preauricular node\n- **Allergic conjunctivitis**: Itchy, bilateral, seasonal\n- **Subconjunctival hemorrhage**: Painless, bright red, resolves 2 weeks\n\n### Serious (Urgent)\n- **Acute glaucoma**: Severe pain, halos, fixed mid-dilated pupil, hard eye\n- **Anterior uveitis**: Photophobia, perilimbal injection, small pupil\n- **Corneal ulcer**: Pain, photophobia, white opacity, contact lens wearer\n- **Scleritis**: Deep boring pain, violaceous hue\n\n### Red Flags → Ophthalmology\n- Sudden vision loss\n- Severe pain\n- Photophobia\n- Fixed or irregular pupil\n- Corneal opacity\n- History of trauma/chemical exposure''','en','AAO',5,true),
('symptom_guide','ear_pain',ARRAY['otalgia','ear pain','otitis media','otitis externa','ear infection','hearing loss'],'Ear Pain','E''## Ear Pain (Otalgia)\n\n### Primary Ear Causes\n- **Otitis externa**: Swimmer ear, pain on tragus pressure, discharge\n- **Acute otitis media**: Fever, bulging TM, ear pulling (children)\n- **Otitis media with effusion**: Hearing loss, fluid behind TM\n- **Cerumen impaction**: Fullness, hearing loss\n- **Foreign body**: Children, unilateral\n\n### Referred Pain\n- TMJ dysfunction (jaw clenching)\n- Dental pathology (wisdom teeth)\n- Pharyngitis/tonsillitis\n- Cervical spine disease\n\n### Treatment\n- **AOM**: Amoxicillin 80-90mg/kg/day (children) × 5-10 days\n- **AOE**: Topical ciprofloxacin-dexamethasone drops × 7 days\n- **OME**: Watch & wait 3 months, then consider grommets\n\n### Red Flags\n- Mastoid tenderness → mastoiditis\n- Facial nerve palsy → urgent ENT\n- Blood/CSF from ear after trauma → skull fracture''','en','AAO-HNS',5,true),
('symptom_guide','back_pain',ARRAY['back pain','lumbar','sciatica','disc herniation','spinal stenosis','red flags'],'Back Pain','E''## Back Pain Assessment\n\n### Classification\n- **Mechanical (90%)**: Muscle strain, degenerative disc, facet joint\n- **Radiculopathy**: Sciatica (dermatomal pain, numbness, weakness)\n- **Serious pathology (<5%)**: Fracture, malignancy, infection, cauda equina\n\n### Red Flags (require urgent investigation)\n- Saddle anesthesia / bowel-bladder dysfunction → cauda equina\n- Progressive motor weakness\n- Age >50 with new onset + weight loss → malignancy\n- Fever + back pain → spinal infection\n- Trauma + osteoporosis → fracture\n\n### Management (Non-specific)\n- Stay active (bed rest NOT recommended)\n- NSAIDs (Ibuprofen/Diclofenac) first-line\n- Paracetamol as adjunct\n- Physiotherapy after 2-4 weeks\n- MRI only if red flags or no improvement at 6 weeks\n\n### Sciatica\n- Conservative management × 6-8 weeks\n- Gabapentin/Pregabalin for neuropathic pain\n- Surgery if progressive deficit or cauda equina''','en','NICE',5,true),
('symptom_guide','weight_loss',ARRAY['weight loss','unintentional','malignancy','thyroid','diabetes','cachexia'],'Unintentional Weight Loss','E''## Unintentional Weight Loss\n\n### Definition\n- ≥5% body weight over 6-12 months without trying\n\n### Differential Diagnosis\n- **Malignancy**: Any cancer, especially GI, lung, lymphoma\n- **Endocrine**: Hyperthyroidism, diabetes, adrenal insufficiency\n- **GI**: Celiac disease, IBD, malabsorption, chronic diarrhea\n- **Infection**: TB, HIV, chronic infections\n- **Psychiatric**: Depression, eating disorders, dementia\n- **Chronic disease**: Heart failure, COPD, renal failure\n\n### Workup\n- CBC, ESR/CRP, metabolic panel\n- TFTs, HbA1c, LFTs\n- HIV test, TB screening\n- Chest X-ray\n- Age-appropriate cancer screening\n- CT chest/abdomen if above unrevealing\n\n### Red Flags\n- Age >60 + weight loss → high cancer suspicion\n- Night sweats + fever → TB/lymphoma\n- Dysphagia + weight loss → esophageal/gastric cancer''','en','BMJ',5,true),
('symptom_guide','edema_swelling',ARRAY['edema','swelling','leg swelling','ascites','peripheral edema','pitting'],'Edema & Swelling','E''## Edema Assessment\n\n### Generalized Edema\n- **Heart failure**: Bilateral leg edema, JVP raised, dyspnea\n- **Nephrotic syndrome**: Periorbital + leg edema, proteinuria\n- **Liver cirrhosis**: Ascites + leg edema, jaundice\n- **Hypothyroidism**: Non-pitting, myxedema\n\n### Unilateral Leg Swelling\n- **DVT**: Acute, painful, calf tenderness → D-dimer, Doppler\n- **Cellulitis**: Red, warm, tender, fever\n- **Lymphedema**: Chronic, non-pitting, no pain\n- **Baker cyst rupture**: Behind knee, sudden pain\n\n### Workup\n- Albumin, LFTs, renal function\n- Urinalysis (proteinuria)\n- BNP (heart failure)\n- Doppler US if unilateral\n- Echocardiogram if cardiac cause\n\n### Red Flags\n- Unilateral + sudden → DVT until proven otherwise\n- Edema + dyspnea → heart failure or PE\n- Edema + frothy urine → nephrotic syndrome''','en','BMJ',5,true),
('symptom_guide','sore_throat',ARRAY['sore throat','pharyngitis','tonsillitis','strep throat','centor','rheumatic fever'],'Sore Throat','E''## Sore Throat Assessment\n\n### Centor Criteria (Strep Risk)\n- Fever >38°C (+1)\n- Tonsillar exudate (+1)\n- Tender anterior cervical nodes (+1)\n- Absence of cough (+1)\n- Age 3-14 (+1), Age 15-44 (0), >45 (-1)\n\n### Score Interpretation\n- 0-1: No testing or antibiotics\n- 2-3: Rapid strep test, treat if positive\n- 4-5: Empiric antibiotics\n\n### Treatment\n- **Viral**: Supportive (analgesics, warm fluids)\n- **Strep**: Penicillin V 500mg BD × 10 days\n- **Allergy**: Azithromycin 500mg D1, 250mg D2-5\n\n### Complications\n- Peritonsillar abscess: Trismus, uvula deviation, drooling\n- Rheumatic fever: Joint pain, cardiac involvement\n- Post-strep glomerulonephritis\n\n### Red Flags\n- Unable to swallow saliva → abscess\n- Stridor → epiglottitis (emergency)\n- Bilateral tonsillar enlargement + fatigue → EBV (mono)''','en','NICE',5,true),
('symptom_guide','nausea_vomiting',ARRAY['nausea','vomiting','emesis','gastroenteritis','pregnancy','intracranial pressure'],'Nausea & Vomiting','E''## Nausea & Vomiting\n\n### Common Causes\n- **GI**: Gastroenteritis, gastroparesis, obstruction, appendicitis\n- **CNS**: Migraine, raised ICP, labyrinthitis, meningitis\n- **Metabolic**: DKA, uremia, hypercalcemia, Addison\n- **Drugs**: Opioids, chemotherapy, antibiotics, digoxin\n- **Pregnancy**: Morning sickness, hyperemesis gravidarum\n\n### Red Flags\n- Projectile vomiting + headache → raised ICP\n- Bilious vomiting → bowel obstruction\n- Hematemesis → upper GI bleed\n- Severe dehydration signs\n\n### Management\n- Rehydration (ORS or IV)\n- Antiemetics:\n  - Ondansetron 4-8mg (first-line)\n  - Metoclopramide 10mg (prokinetic)\n  - Domperidone 10mg (if metoclopramide CI)\n- Treat underlying cause\n\n### Pregnancy\n- Ginger, small frequent meals\n- Pyridoxine (B6) + Doxylamine\n- Ondansetron if severe''','en','NICE',5,true),
('symptom_guide','fever_workup',ARRAY['fever','pyrexia','PUO','fever of unknown origin','sepsis','infection'],'Fever Workup','E''## Fever Workup\n\n### Definition\n- Oral temperature ≥38°C (100.4°F)\n- Fever of unknown origin: >38.3°C for >3 weeks, no diagnosis after 1 week\n\n### Common Causes by System\n- **Respiratory**: Pneumonia, TB, COVID\n- **Urinary**: UTI, pyelonephritis\n- **Abdominal**: Appendicitis, cholecystitis, abscess\n- **Skin/Soft tissue**: Cellulitis, abscess\n- **CNS**: Meningitis, encephalitis\n- **Tropical**: Malaria, dengue, typhoid\n\n### Initial Workup\n- CBC with differential\n- Blood cultures ×2\n- Urinalysis + culture\n- Chest X-ray\n- CRP/ESR\n- Malaria smear (endemic areas)\n\n### When to Refer Urgently\n- Fever + petechial rash → meningococcemia\n- Fever + altered consciousness → meningitis/encephalitis\n- Fever + neutropenia → febrile neutropenia\n- Fever + hypotension → sepsis''','en','WHO',5,true),
('symptom_guide','shortness_of_breath',ARRAY['dyspnea','shortness of breath','breathlessness','respiratory distress','wheezing','orthopnea'],'Shortness of Breath','E''## Dyspnea Assessment\n\n### Acute Causes\n- **Asthma exacerbation**: Wheeze, triggers, history\n- **Pneumonia**: Fever, productive cough, crackles\n- **Pulmonary embolism**: Sudden onset, pleuritic pain, risk factors\n- **Pneumothorax**: Sudden, pleuritic, reduced breath sounds\n- **Heart failure**: Orthopnea, PND, bilateral crackles\n- **Anaphylaxis**: Stridor, urticaria, hypotension\n\n### Chronic Causes\n- COPD, interstitial lung disease\n- Heart failure, valvular disease\n- Anemia, obesity, deconditioning\n\n### Initial Assessment\n- SpO2, respiratory rate, work of breathing\n- Peak flow (if asthma suspected)\n- Chest X-ray, ECG\n- ABG if SpO2 <92%\n- D-dimer if PE suspected\n\n### Red Flags\n- SpO2 <90% → immediate oxygen\n- Stridor → anaphylaxis/upper airway obstruction\n- Silent chest in asthma → near-fatal attack\n- Cannot speak in sentences → severe respiratory distress''','en','BTS',5,true);
